import{_ as a,o as t,c as p,ai as s}from"./chunks/framework.CzqNhXfh.js";const m=JSON.parse('{"title":"书后思","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"essays/articles/article-010.md","filePath":"essays/articles/article-010.md","lastUpdated":1776825361000}'),r={name:"essays/articles/article-010.md"};function o(c,e,l,i,_,n){return t(),p("div",null,[...e[0]||(e[0]=[s('<h1 id="书后思" tabindex="-1">书后思 <a class="header-anchor" href="#书后思" aria-label="Permalink to &quot;书后思&quot;">​</a></h1><blockquote><p>子昱 闲谈之余 2022年12月24日 23:53 江西</p></blockquote><p>一个晚上一本书 《第七天》</p><p>人很轻松，很自在，读完之后是一种奇妙的体验。</p><p>首先，其实读书是一件很惬意，也很轻易的事情。随手一拿便开始看了，读毕，深度的思考就涌上脑海，多么享受！这远比电子榨菜和游戏要令人愉悦得多。不从任何其他目的来讲，娱乐形式本无差别。但代入主观体验之后，还是会不自觉得认为，读书是一种高贵的体验！高贵的享受！</p><p>回到这本书，读完《第七天》给我的印象是：奇妙，荒诞，现实，虚幻</p><p>处处是现实，但处处虚幻</p><p>暴露了各种问题，但也展现了人性中的美好，感情的美好。</p><p>余华说，写书时，是带着这些感动写下去的。是啊，尽管各种丑陋层出不穷，可是很难不被那些画面打动！一幕幕的真实，心疼极了！</p><p>我依然很珍贵这种感情的存在，它就在我们身边，所以定要好好把握。不同于那个时代的苦命与颠沛，我们的幸福来的太降临，太自然了。一时间，幸福已在每天每天与我们打招呼。</p><p>抓紧！</p><p>抓紧！</p><p>抓紧！</p><p>多感受美好！</p><p>书！</p>',15)])])}const u=a(r,[["render",o]]);export{m as __pageData,u as default};
